<div class="grid grid-2"><div class="card"><h3>Leave Request</h3><form method="post" action="<?=url('/leave/store')?>"><?=csrf_field()?><label>Employee</label><select name="employee_id"><?php foreach($employees as $e1):?><option value="<?=e($e1['id'])?>"><?=e($e1['full_name'])?></option><?php endforeach;?></select><label>Type</label><select name="leave_type_id"><?php foreach($types as $t):?><option value="<?=e($t['id'])?>"><?=e($t['name'])?></option><?php endforeach;?></select><div class="form-row"><div><label>Start</label><input name="start_date" type="date" required></div><div><label>End</label><input name="end_date" type="date" required></div></div><label>Reason</label><textarea name="reason"></textarea><button class="btn btn-primary">Submit</button></form></div><div class="card"><h3>Requests</h3><table class="table"><tr><th>Employee</th><th>Type</th><th>Dates</th><th>Status</th><th></th></tr><?php foreach($rows as $r):?><tr><td><?=e($r['full_name'])?></td><td><?=e($r['leave_type'])?></td><td><?=e($r['start_date'])?> - <?=e($r['end_date'])?></td><td><span class="badge badge-warning"><?=e($r['status'])?></span></td><td><?php if($r['status']==='pending'):?><form method="post" action="<?=url('/leave/approve')?>"><?=csrf_field()?><input type="hidden" name="id" value="<?=e($r['id'])?>"><button class="btn btn-light">Approve</button></form><?php endif;?></td></tr><?php endforeach;?></table></div></div>
